final:
module RefModule(
    input  D,
    output Q,
    input  RESET,
    input  SET,
    input  CLK_N
);reg unused_Q_reg;

always @ (negedge CLK_N) begin
    if (RESET) begin
        unused_Q_reg <= 0;
    end else if (SET) begin
        unused_Q_reg <= 1;
    end else begin
        unused_Q_reg <= D;
    end
end

assign Q = unused_Q_reg;

endmodule
